<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>2048 Game</title>
  <style>
    :root {
      --bg-color: #121212;
      --board-bg: #1e1e1e;
      --grid-gap: 12px;
      --tile-size: 80px;
      --text-color: #ffffff;
    }

    body {
      background-color: var(--bg-color);
      color: var(--text-color);
      font-family: 'Helvetica Neue', Arial, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      margin: 0;
      user-select: none;
    }

    .container {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 20px;
    }

    header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      width: 100%;
      max-width: 380px;
    }

    h1 {
      font-size: 40px;
      margin: 0;
      font-weight: bold;
      letter-spacing: 1px;
    }

    .stats-actions {
      display: flex;
      flex-direction: column;
      align-items: flex-end;
      gap: 10px;
    }

    .score-container {
      background-color: #2a2a2a;
      padding: 8px 16px;
      border-radius: 6px;
      font-size: 14px;
      text-transform: uppercase;
      text-align: center;
      min-width: 80px;
    }

    #score {
      display: block;
      font-size: 24px;
      font-weight: bold;
      color: #fff;
    }

    #reset {
      background-color: #8f7a66;
      color: #fff;
      border: none;
      padding: 10px 20px;
      border-radius: 6px;
      font-weight: bold;
      cursor: pointer;
      font-size: 16px;
      transition: background-color 0.2s;
    }

    #reset:hover {
      background-color: #9f8a76;
    }

    #board {
      background-color: var(--board-bg);
      width: calc(var(--tile-size) * 4 + var(--grid-gap) * 5);
      height: calc(var(--tile-size) * 4 + var(--grid-gap) * 5);
      border-radius: 8px;
      padding: var(--grid-gap);
      display: grid;
      grid-template-columns: repeat(4, var(--tile-size));
      grid-template-rows: repeat(4, var(--tile-size));
      gap: var(--grid-gap);
      box-sizing: border-box;
      position: relative;
    }

    .tile {
      width: var(--tile-size);
      height: var(--tile-size);
      border-radius: 6px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 28px;
      font-weight: bold;
      transition: all 0.1s ease-in-out;
      box-sizing: border-box;
    }

    /* Dark theme tile colors */
    .tile-0 { background-color: #2c2c2c; color: transparent; }
    .tile-2 { background-color: #3e3e3e; color: #eee; }
    .tile-4 { background-color: #4a4a4a; color: #eee; }
    .tile-8 { background-color: #f2b179; color: #f9f6f2; }
    .tile-16 { background-color: #f59563; color: #f9f6f2; }
    .tile-32 { background-color: #f67c5f; color: #f9f6f2; }
    .tile-64 { background-color: #f65e3b; color: #f9f6f2; }
    .tile-128 { background-color: #edcf72; color: #f9f6f2; box-shadow: 0 0 8px #edcf72; }
    .tile-256 { background-color: #edcc61; color: #f9f6f2; box-shadow: 0 0 10px #edcc61; }
    .tile-512 { background-color: #edc850; color: #f9f6f2; box-shadow: 0 0 12px #edc850; }
    .tile-1024 { background-color: #edc53f; color: #f9f6f2; box-shadow: 0 0 14px #edc53f; font-size: 24px; }
    .tile-2048 { background-color: #edc22e; color: #f9f6f2; box-shadow: 0 0 16px #edc22e; font-size: 24px; }
    .tile-super { background-color: #3c3a32; color: #f9f6f2; font-size: 20px; }

    .game-over {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: rgba(0, 0, 0, 0.8);
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      border-radius: 8px;
      font-size: 32px;
      font-weight: bold;
      color: #fff;
      z-index: 10;
      display: none;
    }
  </style>
</head>
<body>

  <div class="container">
    <header>
      <h1>2048</h1>
      <div class="stats-actions">
        <div class="score-container">
          Score
          <span id="score">0</span>
        </div>
        <button id="reset">New Game</button>
      </div>
    </header>

    <div style="position: relative;">
      <div id="board"></div>
      <div id="game-over" class="game-over">
        Game Over!
      </div>
    </div>
  </div>

  <script>
    const SIZE = 4;
    let grid = Array(SIZE).fill(null).map(() => Array(SIZE).fill(0));
    let currentScore = 0;

    const boardEl = document.getElementById('board');
    const scoreEl = document.getElementById('score');
    const resetBtn = document.getElementById('reset');
    const gameOverEl = document.getElementById('game-over');

    // Helper to render the board UI
    function render() {
      boardEl.innerHTML = '';
      for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
          const val = grid[r][c];
          const tile = document.createElement('div');
          tile.className = `tile tile-${val > 2048 ? 'super' : val}`;
          tile.textContent = val > 0 ? val : '';
          boardEl.appendChild(tile);
        }
      }
      scoreEl.textContent = currentScore;

      if (isGameOver()) {
        gameOverEl.style.display = 'flex';
      } else {
        gameOverEl.style.display = 'none';
      }
    }

    // Spawn a random tile (2 or 4) in an empty cell
    function spawnTile() {
      const emptyCells = [];
      for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
          if (grid[r][c] === 0) {
            emptyCells.push({ r, c });
          }
        }
      }
      if (emptyCells.length > 0) {
        const { r, c } = emptyCells[Math.floor(Math.random() * emptyCells.length)];
        grid[r][c] = Math.random() < 0.9 ? 2 : 4;
      }
    }

    // Check if any moves are possible
    function isGameOver() {
      for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
          if (grid[r][c] === 0) return false;
          if (r < SIZE - 1 && grid[r][c] === grid[r + 1][c]) return false;
          if (c < SIZE - 1 && grid[r][c] === grid[r][c + 1]) return false;
        }
      }
      return true;
    }

    // Slide and merge a single row/column array
    function slideAndMerge(line) {
      // Filter out zeros
      let filtered = line.filter(val => val !== 0);
      let merged = [];
      let scoreGain = 0;

      for (let i = 0; i < filtered.length; i++) {
        if (i < filtered.length - 1 && filtered[i] === filtered[i + 1]) {
          const mergedVal = filtered[i] * 2;
          merged.push(mergedVal);
          scoreGain += mergedVal;
          i++; // Skip next element as it merged
        } else {
          merged.push(filtered[i]);
        }
      }

      // Pad with zeros to original length
      while (merged.length < line.length) {
        merged.push(0);
      }

      return { line: merged, scoreGain };
    }

    // Core move logic
    function executeMove(direction) {
      let changed = false;
      let totalScoreGain = 0;

      if (direction === 'left') {
        for (let r = 0; r < SIZE; r++) {
          const original = [...grid[r]];
          const { line, scoreGain } = slideAndMerge(original);
          if (JSON.stringify(original) !== JSON.stringify(line)) {
            changed = true;
          }
          grid[r] = line;
          totalScoreGain += scoreGain;
        }
      } else if (direction === 'right') {
        for (let r = 0; r < SIZE; r++) {
          const original = [...grid[r]];
          const reversed = [...original].reverse();
          const { line, scoreGain } = slideAndMerge(reversed);
          const finalLine = line.reverse();
          if (JSON.stringify(original) !== JSON.stringify(finalLine)) {
            changed = true;
          }
          grid[r] = finalLine;
          totalScoreGain += scoreGain;
        }
      } else if (direction === 'up') {
        for (let c = 0; c < SIZE; c++) {
          const original = [];
          for (let r = 0; r < SIZE; r++) original.push(grid[r][c]);
          const { line, scoreGain } = slideAndMerge(original);
          if (JSON.stringify(original) !== JSON.stringify(line)) {
            changed = true;
          }
          for (let r = 0; r < SIZE; r++) {
            grid[r][c] = line[r];
          }
          totalScoreGain += scoreGain;
        }
      } else if (direction === 'down') {
        for (let c = 0; c < SIZE; c++) {
          const original = [];
          for (let r = 0; r < SIZE; r++) original.push(grid[r][c]);
          const reversed = [...original].reverse();
          const { line, scoreGain } = slideAndMerge(reversed);
          const finalLine = line.reverse();
          if (JSON.stringify(original) !== JSON.stringify(finalLine)) {
            changed = true;
          }
          for (let r = 0; r < SIZE; r++) {
            grid[r][c] = finalLine[r];
          }
          totalScoreGain += scoreGain;
        }
      }

      if (changed) {
        currentScore += totalScoreGain;
      }
      return { changed };
    }

    // Initialize a new game
    function initGame() {
      grid = Array(SIZE).fill(null).map(() => Array(SIZE).fill(0));
      currentScore = 0;
      spawnTile();
      spawnTile();
      render();
    }

    // Event Listeners
    resetBtn.addEventListener('click', initGame);

    window.addEventListener('keydown', (e) => {
      let direction = null;
      if (e.key === 'ArrowLeft') direction = 'left';
      else if (e.key === 'ArrowRight') direction = 'right';
      else if (e.key === 'ArrowUp') direction = 'up';
      else if (e.key === 'ArrowDown') direction = 'down';

      if (direction) {
        e.preventDefault();
        const { changed } = executeMove(direction);
        if (changed) {
          spawnTile();
          render();
        }
      }
    });

    // Programmatic API
    window.game = {
      size: SIZE,
      reset() {
        initGame();
      },
      move(direction) {
        const { changed } = executeMove(direction);
        if (changed) {
          spawnTile();
          render();
        }
        return changed;
      },
      board() {
        // Return a deep copy of the grid
        return grid.map(row => [...row]);
      },
      setBoard(arr) {
        // Expects a 4x4 array of numbers
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            grid[r][c] = arr[r][c];
          }
        }
        render();
      },
      score() {
        return currentScore;
      }
    };

    // Start game on load
    initGame();
  </script>
</body>
</html>
